class Solution:
    def getImportance(self, employees: List['Employee'], id: int) -> int:
        mp={e.id:e for e in employees}
        def dfs(i):
            e=mp[i]; s=e.importance
            for sub in e.subordinates: s+=dfs(sub)
            return s
        return dfs(id)

