class Solution {
public:
    int getImportance(vector<Employee*> employees, int id) {
        unordered_map<int,Employee*> mp;
        for(auto e:employees) mp[e->id]=e;
        function<int(int)> dfs=[&](int i){
            int s=mp[i]->importance;
            for(int sub:mp[i]->subordinates) s+=dfs(sub);
            return s;
        };
        return dfs(id);
    }
};

