int getImportance690(int** emp,int n,int id) {
    int idx=-1; for(int i=0;i<n;i++) if(emp[i][0]==id){idx=i;break;}
    if(idx<0) return 0;
    int sum=emp[idx][1];
    for(int j=2;j<emp[idx][2]+2;j++) sum+=getImportance690(emp,n,emp[idx][j]);
    return sum;
}
